#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, a[25], k, ans = 0;
bool f(int a)
{
	for (int i = 2; i * i <= a; ++i)
		if (a % i == 0)return false;
	return true;
}
void dfs(int pos, int sum, int d)
{
	if (pos == k && f(sum))++ans;
	for (int i = d; i <= n; i++)dfs(pos + 1, sum + a[i], i + 1);
}
int main(void)
{
	cin >> n >> k;
	for (int i = 1; i <= n; ++i)cin >> a[i];
	dfs(0, 0, 1);
	cout << ans;
	return false;
}
